SELECT COUNT(*) AS QTDE_PRODUCOES FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB LP ON LPB.FK_PRODBIB = LP.PK JOIN SERVIDOR S ON LPB.FK_SIAPE = S.PK_SIAPE WHERE LP.NATUREZA = 'RESUMO' AND LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%sociologia%') AND S.GENERO = 'MASCULINO' AND LP.ANO = '2024'